/* =============================================================================
   AURA ALPHA -- Forex Dashboard
   Currency strength meter, major pairs table with signals, economic calendar.
   Wired to: GET /api/forex/pairs, /api/forex/strength, /api/forex/calendar,
             GET /api/signals, GET /api/scanners/signals/live
   ============================================================================= */
import { useState, useEffect, useCallback, useRef } from 'react';
import { getApiBase } from '../utils/platform';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import s from './ForexPage.module.css';

const API = getApiBase();
const PAIR_TABS = ['All', 'Major', 'Minor', 'Exotic'];
const POLL_MS = 30_000;
const CALENDAR_IMPACT = ['All', 'High', 'Medium', 'Low'];

/* -------------------------------------------------------------------------- */
/*  Helpers                                                                    */
/* -------------------------------------------------------------------------- */

function safeFetch(url) {
  return fetch(url).then(r => {
    if (!r.ok) throw new Error(`${r.status} ${r.statusText}`);
    return r.json();
  });
}

function fmtRate(val, pair) {
  if (val == null || isNaN(val)) return '--';
  // JPY pairs use 3 decimals, others use 5
  const isJpy = pair && (pair.includes('JPY') || pair.includes('HUF'));
  return Number(val).toFixed(isJpy ? 3 : 5);
}

function pctColor(v) {
  if (v > 0) return 'var(--color-green, #3FB950)';
  if (v < 0) return 'var(--color-red, #F85149)';
  return 'var(--color-text-secondary, #8B949E)';
}

function signalBadge(direction) {
  if (!direction) return null;
  const d = direction.toUpperCase();
  if (d === 'BUY' || d === 'LONG' || d === 'BULLISH')
    return { label: d, bg: 'rgba(63,185,80,0.12)', color: '#3FB950', border: 'rgba(63,185,80,0.3)' };
  if (d === 'SELL' || d === 'SHORT' || d === 'BEARISH')
    return { label: d, bg: 'rgba(248,81,73,0.12)', color: '#F85149', border: 'rgba(248,81,73,0.3)' };
  return { label: d, bg: 'rgba(88,166,255,0.10)', color: '#58A6FF', border: 'rgba(88,166,255,0.2)' };
}

function impactColor(impact) {
  if (!impact) return 'var(--color-text-secondary)';
  const i = impact.toLowerCase();
  if (i === 'high') return 'var(--color-red, #F85149)';
  if (i === 'medium') return 'var(--color-amber, #D29922)';
  return 'var(--color-text-secondary, #8B949E)';
}

/* -------------------------------------------------------------------------- */
/*  Sub-components                                                             */
/* -------------------------------------------------------------------------- */

function StrengthBar({ value, currency }) {
  const absVal = Math.abs(value);
  const color = value > 0 ? 'var(--color-green, #3FB950)' : value < 0 ? 'var(--color-red, #F85149)' : 'var(--color-text-secondary)';
  const width = Math.min(100, absVal);
  const isPositive = value >= 0;
  return (
    <div className={s.strengthRow}>
      <span className={s.strengthCurrency}>{currency}</span>
      <div className={s.strengthTrack}>
        <div className={s.strengthCenter} />
        <div
          className={s.strengthBar}
          style={{
            left: isPositive ? '50%' : `${50 - width / 2}%`,
            width: `${width / 2}%`,
            background: color,
          }}
        />
      </div>
      <span className={s.strengthValue} style={{ color }}>
        {value > 0 ? '+' : ''}{Number(value).toFixed(1)}
      </span>
    </div>
  );
}

function SignalBadge({ direction }) {
  const badge = signalBadge(direction);
  if (!badge) return null;
  return (
    <span className={s.signalBadge} style={{
      background: badge.bg, color: badge.color, border: `1px solid ${badge.border}`,
    }}>
      {badge.label}
    </span>
  );
}

/* -------------------------------------------------------------------------- */
/*  Main Page                                                                  */
/* -------------------------------------------------------------------------- */

export default function ForexPage() {
  usePageTitle('Forex');

  const [activeTab, setActiveTab] = useState('All');
  const [pairs, setPairs] = useState([]);
  const [strength, setStrength] = useState(null);
  const [calendar, setCalendar] = useState([]);
  const [signals, setSignals] = useState({});
  const [calendarFilter, setCalendarFilter] = useState('All');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [lastUpdate, setLastUpdate] = useState(null);
  const pollRef = useRef(null);

  /* -- Build signal lookup by symbol -- */
  const buildSignalMap = useCallback((signalList) => {
    const map = {};
    if (!Array.isArray(signalList)) return map;
    for (const sig of signalList) {
      const sym = sig.symbol || sig.pair || sig.ticker;
      if (sym) map[sym.toUpperCase()] = sig;
    }
    return map;
  }, []);

  /* -- Fetch all data -- */
  const fetchData = useCallback(async (showLoading) => {
    if (showLoading) setLoading(true);
    setError(null);
    try {
      const results = await Promise.allSettled([
        safeFetch(`${API}/forex/pairs`),
        safeFetch(`${API}/forex/strength`),
        safeFetch(`${API}/forex/calendar`),
        safeFetch(`${API}/scanners/signals/live`),
        safeFetch(`${API}/signals?asset_class=forex`),
      ]);

      // Pairs
      const pairsRes = results[0];
      if (pairsRes.status === 'fulfilled') {
        const d = pairsRes.value;
        setPairs(Array.isArray(d) ? d : d?.pairs || d?.data || []);
      }

      // Strength
      const strengthRes = results[1];
      if (strengthRes.status === 'fulfilled') {
        setStrength(strengthRes.value);
      }

      // Calendar
      const calRes = results[2];
      if (calRes.status === 'fulfilled') {
        const d = calRes.value;
        setCalendar(Array.isArray(d) ? d : d?.events || d?.data || []);
      }

      // Signals -- merge live scanner + filtered signals
      const sigMap = {};
      const liveRes = results[3];
      if (liveRes.status === 'fulfilled') {
        const live = liveRes.value;
        const arr = Array.isArray(live) ? live : live?.signals || live?.data || [];
        Object.assign(sigMap, buildSignalMap(arr.filter(s =>
          (s.asset_class || '').toLowerCase() === 'forex' ||
          (s.region || '').toLowerCase() === 'forex' ||
          (s.symbol || '').includes('/')
        )));
      }
      const filtRes = results[4];
      if (filtRes.status === 'fulfilled') {
        const filt = filtRes.value;
        const arr = Array.isArray(filt) ? filt : filt?.signals || filt?.data || [];
        Object.assign(sigMap, buildSignalMap(arr));
      }
      setSignals(sigMap);
      setLastUpdate(new Date());

      // If all major fetches failed, show error
      if (pairsRes.status === 'rejected' && strengthRes.status === 'rejected') {
        setError('Unable to connect to forex data endpoints');
      }
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, [buildSignalMap]);

  /* -- Initial load + polling -- */
  useEffect(() => {
    fetchData(true);
    pollRef.current = setInterval(() => fetchData(false), POLL_MS);
    return () => clearInterval(pollRef.current);
  }, [fetchData]);

  /* -- Filter pairs by tab -- */
  const filteredPairs = pairs.filter(p => {
    if (activeTab === 'All') return true;
    const cat = (p.category || p.type || '').toLowerCase();
    return cat === activeTab.toLowerCase();
  });

  /* -- Filter calendar by impact -- */
  const filteredCalendar = calendar.filter(e => {
    if (calendarFilter === 'All') return true;
    return (e.impact || '').toLowerCase() === calendarFilter.toLowerCase();
  });

  /* -- Strength data -- */
  const strengthCurrencies = strength?.currencies || strength?.data
    ? Object.keys(strength.data || strength.strength || {})
    : [];
  const strengthValues = strength?.strength || strength?.data || {};
  const strongest = strength?.strongest || '';
  const weakest = strength?.weakest || '';

  // If strength comes as an array
  const strengthArr = Array.isArray(strength)
    ? strength
    : strengthCurrencies.map(c => ({ currency: c, value: strengthValues[c] || 0 }));

  // Sort by value desc
  const sortedStrength = [...strengthArr].sort((a, b) => (b.value || b.strength || 0) - (a.value || a.strength || 0));

  return (
    <div className={s.pageRoot}>
      {/* Header */}
      <div className={s.header}>
        <div className={s.headerTop}>
          <div>
            <h1 className={s.headerTitle}>Forex Dashboard</h1>
            <p className={s.headerSub}>
              Currency strength, major pairs with signals, and economic calendar
            </p>
          </div>
          {lastUpdate && (
            <span className={s.lastUpdate}>
              Updated {lastUpdate.toLocaleTimeString()}
            </span>
          )}
        </div>
      </div>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>{error}</div>
        </GlassPanel>
      )}

      {loading && (
        <div className={s.loading}>Loading forex data...</div>
      )}

      {!loading && (
        <>
          {/* ── Top Row: Currency Strength + Stats ──────────────────── */}
          <div className={s.topGrid}>
            {/* Currency Strength Meter */}
            <GlassPanel>
              <div className={s.heatmapHeader}>
                <span className={s.heatmapTitle}>Currency Strength Meter</span>
                {(strongest || weakest) && (
                  <div className={s.heatmapMeta}>
                    {strongest && <span className={s.heatmapStrongest}>Strongest: {strongest}</span>}
                    {weakest && <span className={s.heatmapWeakest}>Weakest: {weakest}</span>}
                  </div>
                )}
              </div>
              {sortedStrength.length > 0 ? (
                sortedStrength.map(item => (
                  <StrengthBar
                    key={item.currency || item.code}
                    currency={item.currency || item.code}
                    value={item.value ?? item.strength ?? 0}
                  />
                ))
              ) : (
                <div className={s.emptyHeatmap}>
                  No currency strength data available
                </div>
              )}
            </GlassPanel>

            {/* Quick Stats / Active Signals Summary */}
            <GlassPanel>
              <div className={s.heatmapTitle} style={{ marginBottom: 16 }}>Market Overview</div>
              <div className={s.statsGrid}>
                <div className={s.statCard}>
                  <div className={s.statLabel}>Total Pairs</div>
                  <div className={s.statValueBlue}>{pairs.length}</div>
                </div>
                <div className={s.statCard}>
                  <div className={s.statLabel}>Active Signals</div>
                  <div className={s.statValueGreen}>{Object.keys(signals).length}</div>
                </div>
                <div className={s.statCard}>
                  <div className={s.statLabel}>Calendar Events</div>
                  <div className={s.statValueAmber}>{calendar.length}</div>
                </div>
                <div className={s.statCard}>
                  <div className={s.statLabel}>High Impact</div>
                  <div className={s.statValueRed}>
                    {calendar.filter(e => (e.impact || '').toLowerCase() === 'high').length}
                  </div>
                </div>
              </div>
              {/* Major movers */}
              <div className={s.moversSection}>
                <div className={s.moversTitle}>Top Movers</div>
                {[...pairs]
                  .filter(p => p.change_pct != null)
                  .sort((a, b) => Math.abs(b.change_pct || 0) - Math.abs(a.change_pct || 0))
                  .slice(0, 5)
                  .map(p => (
                    <div key={p.pair || p.symbol} className={s.moverRow}>
                      <span className={s.moverSymbol}>{p.pair || p.symbol}</span>
                      <span className={s.moverPct} style={{ color: pctColor(p.change_pct) }}>
                        {p.change_pct > 0 ? '+' : ''}{(p.change_pct || 0).toFixed(3)}%
                      </span>
                    </div>
                  ))
                }
                {pairs.filter(p => p.change_pct != null).length === 0 && (
                  <div className={s.emptyHeatmap}>No mover data yet</div>
                )}
              </div>
            </GlassPanel>
          </div>

          {/* ── Pair Tabs ───────────────────────────────────────────── */}
          <div className={s.sectionHeader}>
            <span className={s.sectionTitle}>Forex Pairs</span>
            <div className={s.pairTabs}>
              {PAIR_TABS.map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={activeTab === tab ? s.pairTabBtnActive : s.pairTabBtn}
                >
                  {tab}
                  {tab !== 'All' && (
                    <span className={s.tabCount}>
                      ({pairs.filter(p => (p.category || p.type || '').toLowerCase() === tab.toLowerCase()).length})
                    </span>
                  )}
                </button>
              ))}
            </div>
          </div>

          {/* ── Pairs Table ─────────────────────────────────────────── */}
          <GlassPanel className={s.tablePanel}>
            <div className={s.scrollArea}>
              <table className={s.table}>
                <thead className={s.thead}>
                  <tr>
                    {['Pair', 'Rate', 'Change', 'Change %', 'High', 'Low', 'Spread', 'Signal'].map(h => (
                      <th key={h} className={s.th}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filteredPairs.map(p => {
                    const sym = p.pair || p.symbol || '';
                    const sig = signals[sym.toUpperCase()] || signals[sym.replace('/', '').toUpperCase()];
                    const changeColor = pctColor(p.change_pct);
                    return (
                      <tr key={sym} className={s.pairRow}>
                        <td className={s.tdPair}>
                          <span className={s.pairSymbol}>{sym}</span>
                          {p.category && (
                            <span className={s.pairCategoryBadge}>{p.category}</span>
                          )}
                        </td>
                        <td className={s.tdRate}>{fmtRate(p.rate || p.price || p.last, sym)}</td>
                        <td className={s.tdChange} style={{ color: changeColor }}>
                          {p.change != null ? (p.change > 0 ? '+' : '') + fmtRate(p.change, sym) : '--'}
                        </td>
                        <td className={s.tdChangePct} style={{ color: changeColor }}>
                          {p.change_pct != null ? (p.change_pct > 0 ? '+' : '') + (p.change_pct).toFixed(3) + '%' : '--'}
                        </td>
                        <td className={s.tdMono}>{p.high != null ? fmtRate(p.high, sym) : '--'}</td>
                        <td className={s.tdMono}>{p.low != null ? fmtRate(p.low, sym) : '--'}</td>
                        <td className={s.tdMono}>{p.spread != null ? p.spread.toFixed(1) : '--'}</td>
                        <td className={s.tdSignal}>
                          {sig ? (
                            <SignalBadge direction={sig.direction || sig.signal || sig.side} />
                          ) : (
                            <span className={s.noSignal}>--</span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            {filteredPairs.length === 0 && (
              <div className={s.emptyState}>
                <div className={s.emptyText}>No pairs found for this category</div>
              </div>
            )}
          </GlassPanel>

          {/* ── Economic Calendar ──────────────────────────────────── */}
          <div className={s.sectionHeader} style={{ marginTop: 24 }}>
            <span className={s.sectionTitle}>Economic Calendar</span>
            <div className={s.pairTabs}>
              {CALENDAR_IMPACT.map(imp => (
                <button
                  key={imp}
                  onClick={() => setCalendarFilter(imp)}
                  className={calendarFilter === imp ? s.pairTabBtnActive : s.pairTabBtn}
                >
                  {imp}
                </button>
              ))}
            </div>
          </div>

          <GlassPanel className={s.tablePanel}>
            <div className={s.scrollArea}>
              <table className={s.table}>
                <thead className={s.thead}>
                  <tr>
                    {['Time', 'Currency', 'Event', 'Impact', 'Actual', 'Forecast', 'Previous'].map(h => (
                      <th key={h} className={s.th}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filteredCalendar.map((evt, i) => (
                    <tr key={evt.id || i} className={s.calendarRow}>
                      <td className={s.tdMono}>{evt.time || evt.datetime || '--'}</td>
                      <td className={s.tdCurrency}>
                        <span className={s.currencyTag}>{evt.currency || evt.country || '--'}</span>
                      </td>
                      <td className={s.tdEvent}>{evt.event || evt.title || evt.name || '--'}</td>
                      <td className={s.tdImpact}>
                        <span className={s.impactDot} style={{ background: impactColor(evt.impact) }} />
                        <span style={{ color: impactColor(evt.impact) }}>{evt.impact || '--'}</span>
                      </td>
                      <td className={s.tdMono} style={{
                        color: evt.actual != null
                          ? (evt.forecast != null && evt.actual > evt.forecast ? 'var(--color-green, #3FB950)' : 'var(--color-red, #F85149)')
                          : 'var(--color-text-secondary)'
                      }}>
                        {evt.actual ?? '--'}
                      </td>
                      <td className={s.tdMono}>{evt.forecast ?? '--'}</td>
                      <td className={s.tdMono}>{evt.previous ?? '--'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            {filteredCalendar.length === 0 && (
              <div className={s.emptyState}>
                <div className={s.emptyText}>No calendar events found</div>
              </div>
            )}
          </GlassPanel>
        </>
      )}
    </div>
  );
}
